namespace sv_2c07d4f38a8e49c094ed94cd79c1893c.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@page "/chat"
@rendermode InteractiveServer
@using sv_2c07d4f38a8e49c094ed94cd79c1893c.Services
@inject IChatService ChatService
@inject IJSRuntime JS

<PageTitle>Team Chat</PageTitle>

<div class="chat-layout">
    @* ── Left Sidebar: Channel List ── *@
    <aside class="channel-sidebar" style="width: 20%;">
        <div class="sidebar-header">
            <h5>Channels</h5>
        </div>
        <ul class="channel-list">
            @foreach (var channel in _channels)
            {
                <li class="channel-item @(channel.Id == _activeChannelId ? "active" : "")"
                    @onclick="() => SelectChannelAsync(channel)">
                    <div class="channel-name-row">
                        <span class="channel-name"># @channel.Name</span>
                        @if (channel.UnreadCount > 0)
                        {
                            <span class="unread-badge">@channel.UnreadCount</span>
                        }
                    </div>
                    <span class="channel-desc">@TruncateDescription(channel.Description, 60)</span>
                </li>
            }
        </ul>
    </aside>

    @* ── Main Message Area ── *@
    <section class="message-area" style="width: @(_threadOpen ? "55%" : "80%");">
        @if (_activeChannel is not null)
        {
            <div class="message-header">
                <h5># @_activeChannel.Name</h5>
                <span class="channel-description-full">@_activeChannel.Description</span>
            </div>

            <div class="message-list" @ref="_messageListRef" @onscroll="HandleMainScrollAsync">
                @if (_loadingOlder)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @foreach (var msg in _messages)
                {
                    <div class="message-bubble @(msg.Id == _hoveredMessageId ? "hovered" : "")"
                         @onmouseenter="() => _hoveredMessageId = msg.Id"
                         @onmouseleave="() => { if (_hoveredMessageId == msg.Id) { _hoveredMessageId = null; _emojiPickerMessageId = null; } }">
                        <div class="message-top-row">
                            <span class="msg-author">@msg.Author</span>
                            <span class="msg-time">@FormatRelativeTime(msg.SentAt)</span>
                        </div>
                        <div class="msg-content">@msg.Content</div>

                        @if (msg.Reactions.Count > 0)
                        {
                            <div class="reaction-row">
                                @foreach (var r in msg.Reactions)
                                {
                                    <button class="reaction-badge" @onclick="() => ToggleReactionAsync(msg.Id, r.Emoji)"
                                            title="@string.Join(", ", r.Users)">
                                        @r.Emoji @r.Users.Count
                                    </button>
                                }
                            </div>
                        }

                        @{ var threadInfo = _threadSummaries.GetValueOrDefault(msg.Id); }
                        @if (threadInfo is not null)
                        {
                            <button class="thread-link" @onclick="() => OpenThreadAsync(msg.Id)">
                                @threadInfo.ReplyCount @(threadInfo.ReplyCount == 1 ? "reply" : "replies")
                                — last @FormatRelativeTime(threadInfo.LastReplyAt)
                            </button>
                        }

                        @if (_hoveredMessageId == msg.Id)
                        {
                            <div class="message-actions">
                                <button class="action-btn" title="Reply in thread" @onclick="() => OpenThreadAsync(msg.Id)">💬 Reply</button>
                                <button class="action-btn" title="Add reaction" @onclick="() => ToggleEmojiPicker(msg.Id)">😀 React</button>
                            </div>

                            @if (_emojiPickerMessageId == msg.Id)
                            {
                                <div class="emoji-picker">
                                    @foreach (var emoji in _commonEmojis)
                                    {
                                        <button class="emoji-option" @onclick="() => ToggleReactionAsync(msg.Id, emoji)">@emoji</button>
                                    }
                                </div>
                            }
                        }
                    </div>
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="_newMessageText" @bind:event="oninput"
                          placeholder="Message #@_activeChannel.Name"
                          @onkeydown="HandleMainKeyDownAsync"
                          rows="2"></textarea>
                <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(_newMessageText)"
                        @onclick="SendMainMessageAsync">Send</button>
            </div>
        }
        else
        {
            <div class="empty-state">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ── Right Panel: Thread View ── *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="thread-panel" style="width: 25%;">
            <div class="thread-header">
                <h6>Thread</h6>
                <button class="close-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </div>

            <div class="thread-root-quote">
                <span class="msg-author">@_threadRootMessage.Author</span>
                <span class="msg-time">@FormatRelativeTime(_threadRootMessage.SentAt)</span>
                <div class="msg-content">@_threadRootMessage.Content</div>
            </div>

            <div class="thread-replies">
                @foreach (var reply in _threadReplies)
                {
                    <div class="message-bubble">
                        <div class="message-top-row">
                            <span class="msg-author">@reply.Author</span>
                            <span class="msg-time">@FormatRelativeTime(reply.SentAt)</span>
                        </div>
                        <div class="msg-content">@reply.Content</div>
                        @if (reply.Reactions.Count > 0)
                        {
                            <div class="reaction-row">
                                @foreach (var r in reply.Reactions)
                                {
                                    <button class="reaction-badge" @onclick="() => ToggleReactionAsync(reply.Id, r.Emoji)">
                                        @r.Emoji @r.Users.Count
                                    </button>
                                }
                            </div>
                        }
                    </div>
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="_threadReplyText" @bind:event="oninput"
                          placeholder="Reply…"
                          @onkeydown="HandleThreadKeyDownAsync"
                          rows="2"></textarea>
                <button class="send-btn" disabled="@string.IsNullOrWhiteSpace(_threadReplyText)"
                        @onclick="SendThreadReplyAsync">Reply</button>
            </div>
        </aside>
    }
</div>

@code {
    // ── Common emoji set for the picker ──
    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    // ── State ──
    private List<Channel> _channels = [];
    private List<Message> _messages = [];
    private Dictionary<int, ThreadSummary> _threadSummaries = new();

    private Channel? _activeChannel;
    private int? _activeChannelId;

    private string _newMessageText = string.Empty;
    private string _threadReplyText = string.Empty;

    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;

    // Thread panel
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];
    private int? _activeThreadRootId;

    // Pagination
    private const int PageSize = 30;
    private int _skip;
    private bool _loadingOlder;
    private bool _allOlderLoaded;

    // Element refs
    private ElementReference _messageListRef;

    // ── Lifecycle ──
    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    // ── Channel selection ──
    private async Task SelectChannelAsync(Channel channel)
    {
        _activeChannel = channel;
        _activeChannelId = channel.Id;
        _skip = 0;
        _allOlderLoaded = false;
        _messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _skip = _messages.Count;

        BuildThreadSummaries();
        await ChatService.MarkChannelReadAsync(channel.Id);
        await RefreshChannelBadge(channel.Id);
        await ScrollToBottomAsync();
    }

    // ── Sending messages ──
    private async Task SendMainMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessageText) || _activeChannel is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannel.Id, _newMessageText.Trim(), null);
        _messages.Add(sent);
        _newMessageText = string.Empty;
        _skip++;
        await ScrollToBottomAsync();
    }

    private async Task HandleMainKeyDownAsync(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMainMessageAsync();
        }
    }

    // ── Thread ──
    private async Task OpenThreadAsync(int rootMessageId)
    {
        _activeThreadRootId = rootMessageId;
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        _emojiPickerMessageId = null;

        if (_threadRootMessage is null)
        {
            // Root message might be outside the loaded window; fetch the thread anyway.
            var threadAll = await ChatService.GetThreadAsync(rootMessageId);
            _threadRootMessage = threadAll.FirstOrDefault();
            _threadReplies = threadAll.Skip(1).ToList();
        }
        else
        {
            var threadAll = await ChatService.GetThreadAsync(rootMessageId);
            _threadReplies = threadAll.Where(m => m.Id != rootMessageId).ToList();
        }

        _threadOpen = true;
        _threadReplyText = string.Empty;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _activeThreadRootId = null;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReplyText) || _activeThreadRootId is null || _activeChannel is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannel.Id, _threadReplyText.Trim(), _activeThreadRootId);
        _threadReplies.Add(reply);
        _threadReplyText = string.Empty;

        // Update the thread summary shown in the main list
        _threadSummaries[_activeThreadRootId.Value] = new ThreadSummary(
            _activeThreadRootId.Value,
            _threadReplies.Count,
            reply.SentAt
        );
    }

    private async Task HandleThreadKeyDownAsync(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Reactions ──
    private async Task ToggleReactionAsync(int messageId, string emoji)
    {
        _emojiPickerMessageId = null;
        await ChatService.AddReactionAsync(messageId, emoji);

        // Refresh the message in the local list to reflect the change
        if (_activeChannel is not null)
        {
            var updated = await ChatService.GetMessagesAsync(_activeChannel.Id, 0, _skip);
            _messages = updated;
            BuildThreadSummaries();
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    // ── Pagination (scroll-to-top) ──
    private async Task HandleMainScrollAsync()
    {
        if (_loadingOlder || _allOlderLoaded || _activeChannel is null) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop > 50) return;

        _loadingOlder = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannel.Id, _skip, PageSize);
        if (older.Count == 0)
        {
            _allOlderLoaded = true;
        }
        else
        {
            _messages.InsertRange(0, older);
            _skip += older.Count;
            BuildThreadSummaries();
        }

        _loadingOlder = false;
    }

    // ── Helpers ──
    private void BuildThreadSummaries()
    {
        // Build thread summaries from reply messages that reference a root via ReplyToId
        var replies = _messages.Where(m => m.ReplyToId is not null).ToList();
        _threadSummaries = replies
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(
                g => g.Key,
                g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt))
            );
    }

    private async Task RefreshChannelBadge(int channelId)
    {
        // Re-fetch channels to update unread badges
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task ScrollToBottomAsync()
    {
        await Task.Yield(); // let the render cycle complete
        await JS.InvokeVoidAsync("eval",
            "let el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight;");
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string TruncateDescription(string text, int maxLen)
    {
        if (string.IsNullOrEmpty(text)) return string.Empty;
        return text.Length <= maxLen ? text : text[..(maxLen - 1)] + "…";
    }
}

